INSERT INTO `value` VALUES
(79405,14918,1,NULL,'literal','','Les contenus journalistiques comme révélateurs de la complexité des rapports au vrai et au faux',NULL,1,NULL),
(79406,14918,386,14433,'resource',NULL,NULL,NULL,1,NULL),
(79407,14918,7,NULL,'numeric:timestamp',NULL,'2021-03-19',NULL,1,NULL),
(79408,14918,19,NULL,'literal','','Le milieu journalistique a tendance à considérer les “fake news” comme un phénomène situé à l’extérieur de ses frontières. Il reproduit ainsi une vieille partition entre les institutions médiatiques autorisées à dire et commenter le monde et la grande masse des publics supposée cantonnée à la réception de leurs contenus. Les enquêtes à propos des pratiques informationnelles laissent cependant percevoir une toute autre réalité, où les formes de contenus consommés sont bien plus diversifiées et où les attentes formulées à l’égard des autorités informationnelles forgent une représentation plus riche de ce qui est considéré comme vrai ou faux par les publics. L’intervention identifiera ces attentes et proposera une analyse de contenus journalistiques québécois dans l’espoir de convaincre qu’une attention à produire du fiable sera certainement plus porteuse de bénéfices collectifs que de traquer les infinies variété du faux.',NULL,1,NULL),
(79409,14918,2097,15038,'resource',NULL,NULL,NULL,1,NULL),
(79410,14918,2097,15067,'resource',NULL,NULL,NULL,1,NULL),
(79411,14919,1,NULL,'literal','','Les arcanes du vrai à l’heure des deep fakes : authenticité et dispositifs de véridiction',NULL,1,NULL),
(79412,14919,386,14434,'resource',NULL,NULL,NULL,1,NULL),
(79413,14919,7,NULL,'numeric:timestamp',NULL,'2021-03-26',NULL,1,NULL),
(79414,14919,19,NULL,'literal','','Comme phénomènes de désinformation, les deep fakes suscitent de plus en plus l’inquiétude. L’IA, sur laquelle ils reposent, perfectionne la possibilité de truquer les images et les sons. La technologie étant devenue accessible, la fabrication de deep fakes semble désormais à la portée de tous. Leur multiplication et leur diffusion annoncées sont perçues comme un nouveau facteur de désordre informationnel. En effet, les deep fakes sont un nouvel avatar des “puissances du faux” : ils miment ce qui fait l’authenticité d’un enregistrement audiovisuel tout en brouillant sa référentialité. Que disent les deep fakes des régimes d’interprétation qu’ils supposent et des “arcanes du vrai” à l’ère dite de la “post-vérité” ?',NULL,1,NULL),
(79415,14919,555,16736,'resource',NULL,NULL,NULL,1,NULL),
(79416,14919,1517,NULL,'uri','','','https://www.youtube.com/watch?v=BpyIS_R159w',1,NULL),
(79417,14920,1,NULL,'literal','','Les arcanes du vrai à l’heure des deep fakes : authenticité et dispositifs de véridiction',NULL,1,NULL),
(79418,14920,386,14435,'resource',NULL,NULL,NULL,1,NULL),
(79419,14920,7,NULL,'numeric:timestamp',NULL,'2021-03-26',NULL,1,NULL),
(79420,14920,19,NULL,'literal','','Comme phénomènes de désinformation, les deep fakes suscitent de plus en plus l’inquiétude. L’IA, sur laquelle ils reposent, perfectionne la possibilité de truquer les images et les sons. La technologie étant devenue accessible, la fabrication de deep fakes semble désormais à la portée de tous. Leur multiplication et leur diffusion annoncées sont perçues comme un nouveau facteur de désordre informationnel. En effet, les deep fakes sont un nouvel avatar des “puissances du faux” : ils miment ce qui fait l’authenticité d’un enregistrement audiovisuel tout en brouillant sa référentialité. Que disent les deep fakes des régimes d’interprétation qu’ils supposent et des “arcanes du vrai” à l’ère dite de la “post-vérité” ?',NULL,1,NULL),
(79421,14920,339,NULL,'literal','','La conférence aborde le sujet des deepfakes, en se concentrant sur leur utilisation éducative et satirique, ainsi que sur les questions éthiques et politiques qu\'ils soulèvent. Useille et Toursel présentent des exemples de vidéos deepfake impliquant des personnalités politiques et des célébrités, tout en discutant des intentions des créateurs, de l\'impact sur la désinformation et de la réception du public. Ils abordent différents aspects de la manipulation vidéo, notamment l\'utilisation de techniques sophistiquées telles que l\'intelligence artificielle (IA) et le deep learning, ainsi que des méthodes plus traditionnelles telles que le ralentissement de vidéos pour créer des illusions. Ils discutent également de la nature des images documentaires, de leur lien avec la réalité et de leur capacité à être manipulées. La présentation de vidéos truquées, telles que celles mettant en scène des personnalités politiques comme Nancy Pelosi ou Emmanuel Macron, soulève des questions sur la perception de la réalité, la vérité des images et les implications philosophiques et juridiques de ces manipulations.',NULL,1,NULL),
(79422,14920,2097,13471,'resource',NULL,NULL,NULL,1,NULL),
(79423,14921,1,NULL,'literal','','Figures de l\'automate : des simulacres aux deepfakes',NULL,1,NULL),
(79424,14921,386,14436,'resource',NULL,NULL,NULL,1,NULL),
(79425,14921,7,NULL,'numeric:timestamp',NULL,'2021-03-26',NULL,1,NULL),
(79426,14921,19,NULL,'literal','','Comment les jeunes interprètent-ils le phénomène de l’hypertrucage? Quelles sont les stratégies numériques potentielles que qu’ils utiliseraient pour contrebalancer la désinformation? Des pistes pour guider les éducateurs, les concepteurs de programmes éducatifs et les décideurs dans leur quête pour promouvoir la pensée critique et l\'agentivité des étudiants dans le contexte d\'une désinformation, des données massives, de l\'intelligence artificielle et des médias sociaux.',NULL,1,NULL),
(79427,14921,339,NULL,'literal','','La présentation aborde la question des simulacres à travers l\'histoire, depuis les statues animées dans l\'Égypte ancienne jusqu\'aux avatars numériques contemporains. Elle explore l\'évolution de la notion de simulacre, notamment à travers les travaux philosophiques de Platon et Descartes, ainsi que les avancées technologiques telles que le cinéma et les effets spéciaux. Renée Bourassa discute également des avatars numériques, des deep fakes et de leurs implications éthiques dans le domaine artistique. ',NULL,1,NULL),
(79428,14921,2097,15026,'resource',NULL,NULL,NULL,1,NULL),
(79429,14922,1,NULL,'literal','','Comment les jeunes contrebalancent-ils la désinformation en ligne ?',NULL,1,NULL),
(79430,14922,386,14437,'resource',NULL,NULL,NULL,1,NULL),
(79431,14922,7,NULL,'literal','','2021-03-26',NULL,1,NULL),
(79432,14922,19,NULL,'literal','','Comment les jeunes interprètent-ils le phénomène de l’hypertrucage? Quelles sont les stratégies numériques potentielles que qu’ils utiliseraient pour contrebalancer la désinformation? Des pistes pour guider les éducateurs, les concepteurs de programmes éducatifs et les décideurs dans leur quête pour promouvoir la pensée critique et l\'agentivité des étudiants dans le contexte d\'une désinformation, des données massives, de l\'intelligence artificielle et des médias sociaux.',NULL,1,NULL),
(79433,14922,339,NULL,'literal','','La présentation aborde la lutte contre la désinformation, en particulier contre les hypertrucages, menée par une équipe de chercheurs et chercheuses. Le projet, subventionné par le CRSH et Patrimoine Canada, vise à examiner le potentiel des jeunes à contrer la désinformation et les cybercrimes. Dans la présentation, Nadia Naffi aborde les dangers actuels de la désinformation, la nécessité de solutions basées sur l\'intelligence artificielle, les défis juridiques et les législations existantes dans différents pays, notamment la Californie, la Chine, la France et le Canada. Elle souligne l\'importance de l\'éducation et de la sensibilisation pour aider les jeunes à reconnaître et à contrer la désinformation, ainsi que leur rôle dans la société en tant qu\'acteurs actifs.',NULL,1,NULL),
(79434,14922,2097,13437,'resource',NULL,NULL,NULL,1,NULL),
(79435,14923,1,NULL,'literal','','Y a truc, ça se voit !',NULL,1,NULL),
(79436,14923,386,14438,'resource',NULL,NULL,NULL,1,NULL),
(79437,14923,7,NULL,'numeric:timestamp',NULL,'2021-04-09',NULL,1,NULL),
(79438,14923,19,NULL,'literal','','Les truquages au cinéma sont concomitants à son invention. Ce n’est certainement pas un hasard si le premier découvreur, Georges Méliès, était prestidigitateur. Les techniques de l’illusion alors utilisées ont mué au gré des évolutions technologiques où les astuces artisanales ont fait place à une industrie à part entière. De grandes périodes se dessinent ; truquages directs à la prise de vue, les trucages en post-production, truquages composites. L’arrivée du numérique a engendré une perfection visuelle, où réel et virtuel se confondent comme jamais. Les visual effects ont succédé aux trucages. Mais au fur et à mesure de ses évolutions, notre regard s’est-il transformé ? percevons-nous les images de la même manière que les générations qui nous ont précédés ? A travers différents exemples, nous tenterons de démontrer que l’approche est plus complexe qu’il n’y parait et que si l’image est polysémique, notre perception elle, est multifactorielle.',NULL,1,NULL),
(79439,14923,339,NULL,'literal','','La conférence explore la complexité et l\'évolution des trucages cinématographiques, en mettant l\'accent sur leur impact sur la perception visuelle. L\'orateur, fort de son expérience de 35 ans en enseignement à l\'école Louis-Lumière, souligne l\'importance des trucages historiques, tels que ceux de Méliès, pionnier dans l\'utilisation de la substitution et de la surimpression pour créer des illusions visuelles. Il aborde également l\'évolution vers les trucages modernes, notamment l\'utilisation de la truca et des effets numériques, qui ont transformé la façon dont les films sont perçus aujourd\'hui. La conférence met en lumière la manière dont les perceptions des spectateurs ont évolué avec les avancées technologiques, influencées par les effets spéciaux dans des films récents comme Harry Potter. L\'orateur souligne que notre perception des images est souvent façonnée par des mémorisations antérieures, ce qui influence notre capacité à distinguer le réel de l\'imaginaire. Il conclut en expliquant comment les nouvelles techniques de projection à LED, utilisées dans des films comme \"First Man\", permettent d\'atteindre un réalisme quasi parfait, tout en intégrant des éléments des méthodes traditionnelles de trucage. Cette exploration des trucages met en évidence la relation complexe entre technologie, perception et mémoire visuelle.',NULL,1,NULL),
(79440,14923,86,20208,'resource',NULL,NULL,NULL,1,NULL),
(79441,14924,1,NULL,'literal','','Le réel « performé » des dispositifs ludiques de téléréalité',NULL,1,NULL),
(79442,14924,386,14439,'resource',NULL,NULL,NULL,1,NULL),
(79443,14924,7,NULL,'numeric:timestamp',NULL,'2021-04-09',NULL,1,NULL),
(79444,14924,19,NULL,'literal','','Les émissions de téléréalité ont contribué significativement à transformer la manière dont la télévision « produit » de la réalité et « documente » le réel existant, influençant par là-même notre rapport à l’expérience ainsi que la manière dont nous envisageons la vérité des « événements médiatiques ». Au-delà du « mélange des genres » qu’elle suppose sur le plan des effets de surface et du dispositif, la TR doit être étudiée pour ce qu’elle révèle des constructions énonciatives originales qu’elle engage le téléspectateur à produire et des conséquences de celle-ci sur le statut respectif de la fiction, du documentaire et des jeux en contexte de communication télévisuelle.',NULL,1,NULL),
(79445,14924,339,NULL,'literal','','Dans cette présentation, Pierre Barrette partage ses réflexions sur la télé-réalité, mettant en parallèle ce genre avec le cinéma direct. Il aborde les controverses entourant la télé-réalité, notamment son contenu banal et voyeuriste, ainsi que les questions éthiques liées à l\'exploitation des participants. Il analyse également la nature ludique de la télé-réalité et son impact sur la perception de la réalité et de la vérité. Il compare ensuite la télé-réalité au cinéma direct, soulignant les similitudes dans la création d\'événements médiatiques et la fabulation des participants. La présentation explore la transition entre les formes traditionnelles de cinéma et la montée de la télé-réalité. Elle examine comment les spectateurs interprètent les médias et comment ces médias influencent leur perception de la réalité. L\'accent est mis sur la construction de l\'énonciateur et la distinction entre l\'espace documentaire et l\'espace fictionnel.',NULL,1,NULL),
(79446,14924,2097,15026,'resource',NULL,NULL,NULL,1,NULL),
(79447,14925,1,NULL,'literal','','Les dynamiques de l’autorité : construire la légitimité dans les environnements numériques',NULL,1,NULL),
(79448,14925,386,14440,'resource',NULL,NULL,NULL,1,NULL),
(79449,14925,7,NULL,'numeric:timestamp',NULL,'2021-04-16',NULL,1,NULL),
(79450,14925,19,NULL,'literal','','Comme nous l’explique Hannah Arendt, l’autorité est la capacité de produire confiance sans contrainte physique ou rationnelle. L’espace numérique, en ce sens, regorge d’autorités : nous faisons confiance à un moteur de recherche, à des réseaux sociaux, à des plateformes d’information… Mais comment et pourquoi se produit cette confiance ? Quelles en sont les conditions ? Et quel rôle jouent les grandes compagnies privées dans ces dynamiques d’autorité ?',NULL,1,NULL),
(79451,14925,339,NULL,'literal','','Marcello Vitali-Rosati explore les dynamiques de l\'autorité dans les environnements numériques. Dans cette conférence, il remet en question l\'idée d\'une crise de l\'autorité, soulignant plutôt un déplacement et une reconfiguration des dynamiques. Il utilise la définition d\'autorité d\'Hannah Arendt pour distinguer entre autorité et pouvoir coercitif. Dans l\'espace numérique, la confiance est élevée mais la compréhension des utilisateurs est faible, ce qui soulève des questions sur la source et la légitimité de l\'autorité dans ces espaces. Il discute également de la centralisation croissante du pouvoir et de l\'autorité dans les mains de grandes entreprises technologiques telles que Google, Apple, Facebook et Amazon (GAFA), ainsi que d\'autres entreprises comme Uber et Airbnb. Ces entreprises exercent un contrôle considérable sur nos vies quotidiennes, de la gestion des opérations publiques au contrôle financier. Il met en évidence les implications de cette concentration de pouvoir pour la sécurité publique, les libertés individuelles et la démocratie. Il souligne également l\'importance croissante de plates-formes collaboratives et non lucratives comme Wikipédia comme contre-poids à cette centralisation de l\'autorité.',NULL,1,NULL),
(79452,14925,2097,15038,'resource',NULL,NULL,NULL,1,NULL),
(79453,14926,1,NULL,'literal','','Les fake news au cœur de l’écosystème socionumérique de l’information',NULL,1,NULL),
(79454,14926,386,14441,'resource',NULL,NULL,NULL,1,NULL),
(79455,14926,7,NULL,'numeric:timestamp',NULL,'2021-04-16',NULL,1,NULL),
(79456,14926,19,NULL,'literal','','Loin de n’être que l’habituelle et historique manifestation des tentatives de manipulation de l’information aux fins d’influence, il faut savoir situer l’émergence de ce qu’on appelle désormais fake news dans la spécificité d’un moment de transformation de l’accès à l’information à l’ère de l’internet et des réseaux socionumériques. Les bouleversements dans l’accès à une parole publique et dans la médiation des savoirs, couplés à une profonde crise de défiance vis-à-vis des figures et des discours d’autorité, expliquent les mises en circulation contemporaines de ces infox, fabriquées pour tromper et pour défendre certaines visions du monde.',NULL,1,NULL),
(79457,14926,339,NULL,'literal','','La conférence aborde la complexité croissante de l\'écosystème de l\'information à l\'ère numérique, soulignant l\'impact des réseaux sociaux sur la diffusion et la perception des fake news. Les fake news sont décrites comme un symptôme et un facteur aggravant d\'une crise de confiance envers les figures d\'autorité traditionnelles, telles que les journalistes. Le rôle de gatekeeper des journalistes est remis en question par l\'émergence de citoyens informateurs et la fragmentation de l\'accès à l\'information, exacerbée par une défiance généralisée envers les médias traditionnels. Cette défiance est alimentée par une rhétorique de ressentiment social et une polarisation idéologique, où la post-vérité prédomine, inversant l\'ordre entre faits et opinions. Le paradigme journalistique se transforme en un modèle de changement permanent, nécessitant une agilité numérique pour s\'adapter aux nouveaux médias. La crise de confiance s\'accompagne d\'une haine croissante envers les journalistes, perçus comme des élites déconnectées, et est renforcée par l\'usage des réseaux sociaux pour partager des contenus non vérifiés, souvent conformes aux opinions préexistantes des utilisateurs. Cette dynamique menace les conditions du débat démocratique, qui repose traditionnellement sur un consensus minimal autour des faits, désormais brouillé par l\'importance croissante de l\'opinion sur la réalité factuelle.',NULL,1,NULL),
(79458,14926,86,20871,'resource',NULL,NULL,NULL,1,NULL),
(79459,14927,1,NULL,'literal','','Quels régimes de création dans le médium algorithmique surveillé ?',NULL,1,NULL),
(79460,14927,386,14442,'resource',NULL,NULL,NULL,1,NULL),
(79461,14927,7,NULL,'numeric:timestamp',NULL,'2021-04-23',NULL,1,NULL),
(79462,14927,19,NULL,'literal','','Le déploiement des infrastructures connectées, marqué par une croissance sans précédent ces dernières décennies, semble annoncer plus que jamais la réalisation des dystopies qui mettent en scène des sociétés surveillées. De tels récits, actualisés notamment par les révélations d’Edward Snowden en 2013 (l’interception systémique des communications numériques à l’échelle mondiale par les agences de renseignement) ou le scandale Cambridge Analytica (le ciblage de millions d’internautes à leur insu, grâce à une quantité phénoménale de données béhaviorales), sont présents depuis longtemps dans l’imaginaire social, que ce soit à partir d’œuvres de fiction (1984 de George Orwell) ou de traités philosophiques (Le panoptique de Jeremy Bentham). Dans une démarche croisant la sociologie, la littérature et la philosophie de la technique, nous examinerons l’importance que revêt la prolifération des « technologies de surveillance » (permettant au sens large la captation des données comportementales et biométriques) pour la création artistique. Quelles contraintes ces technologies introduisent-elles pour les créateur·trice·s, d’une part, et quelles potentialités artistiques génèrent-elles, d’autre part ? La réflexion proposée s’achèvera sur une étude de cas de l’auteur.',NULL,1,NULL),
(79463,14927,339,NULL,'literal','','La présentation aborde le passage d\'une société disciplinaire à une société de contrôle, caractérisée par une surveillance de masse et une automatisation croissante de la surveillance systémique. Elle souligne les enjeux éthiques liés à la captation de l\'attention et à la remise en question du libre arbitre philosophique. De plus, elle explore l\'impact du numérique sur la création artistique, mettant en lumière les contraintes et les dangers de la numérisation, ainsi que la nécessité pour les artistes de se réapproprier les langages et les protocoles. ',NULL,1,NULL),
(79464,14927,2097,15038,'resource',NULL,NULL,NULL,1,NULL),
(79465,14928,1,NULL,'literal','','De SMEL (Du spectacle magique au numérique : espaces liminaires de l\'authenticité) aux Arcanes',NULL,1,NULL),
(79466,14928,386,14443,'resource',NULL,NULL,NULL,1,NULL),
(79467,14928,7,NULL,'literal','','2021-04-23',NULL,1,NULL),
(79468,14928,7,NULL,'numeric:timestamp',NULL,'2021-04-23',NULL,1,NULL),
(79469,14928,19,NULL,'literal','','Genèse de l’actuelle recherche sur les ARCANES, le projet SMEL (acronyme pour Du spectacle magique au numérique : espaces liminaires de l’authenticité) mené de 2018 à 2020 s’est plongé dans l’étude du corpus Houdini, célèbre illusionniste prolifique, de la collection d’archives Allan Slaight du Musée McCord à Montréal. Créant des parallèles entre la scène de la magie de la première partie du XXe siècle caractérisée par la révolution électrique et la scène médiatique plus contemporaine chamboulée par l’avènement des pratiques du numérique, le projet SMEL se situe entre l’archéologie des médias et l’expectative de l’intermédialité pour penser l’espace médiatique/numérique d’aujourd’hui autour de l’authenticité et de la médiation. Cette communication énoncera d’abord les objectifs et l’aboutissement de SMEL, puis les raisons de la mutation de cette recherche en ARCANES. Ensuite, elle se concentrera sur les techniques de traitement des sources documentaires employées lors de SMEL pour inventorier le corpus. De la réflexion de l’interopérabilité des données, à l’organisation d’une base de données sémantique jusqu’au premier prototypage d’un dispositif d’éditorialisation, le propos amènera à examiner les expérimentations faites, leurs résultats, et les processus qui nous servent de premières pistes pour penser à l’objectif actuel du développement d’un écosystème de recherche des ARCANES.',NULL,1,NULL),
(79470,14928,339,NULL,'literal','','La présentation concerne les projets de recherche SMEL et ARCANES, qui examinent les intersections entre la magie traditionnelle et les médias numériques contemporains, en mettant l\'accent sur l\'authenticité, la médiation culturelle et les humanités numériques. Le projet vise à étudier les mécanismes de manipulation de l\'information, en particulier à travers l\'analyse des collections du Musée McCord et des pratiques numériques actuelles telles que la propagation de fake news. L\'objectif est de créer un livre numérique savant qui agrège les résultats de la recherche et facilite les discussions scientifiques.',NULL,1,NULL),
(79471,14929,1,NULL,'literal','','Faire entendre l\'inouï : étude d\'une création radiophonique de science-fiction',NULL,1,NULL),
(79472,14929,386,14444,'resource',NULL,NULL,NULL,1,NULL),
(79473,14929,7,NULL,'numeric:timestamp',NULL,'2021-04-23',NULL,1,NULL),
(79474,14929,555,16737,'resource',NULL,NULL,NULL,1,NULL),
(79475,14930,1,NULL,'literal','','Introduction à la 2e édition du séminaire ARCANES : Puissances du faux dans les arts trompeurs et l’écosystème socionumérique',NULL,1,NULL),
(79476,14930,386,14436,'resource',NULL,NULL,NULL,1,NULL),
(79477,14930,7,NULL,'numeric:timestamp',NULL,'2021-10-08',NULL,1,NULL),
(79478,14930,19,NULL,'literal','','Ce séminaire international de cycles supérieurs vise à explorer les mécanismes à l’œuvre dans les arts trompeurs et l’espace informationnel de l’écosystème socionumérique qui activent les puissances du faux, prenant place dans une ère de post-vérité. Cette situation engendre des transformations majeures des systèmes de vérité, d’autorité et de légitimité à l’œuvre dans les dynamiques de médiation contemporaines. Nous explorerons également les filiations entre ces phénomènes contemporains et l’histoire des médias dans une perspective d’intermédialité. Les objets de recherche visés sont situés à la fois dans la sphère des « arts trompeurs », soit des arts recourant à la fois aux pratiques illusionnistes et aux modes fictionnels en utilisant des stratégies de tromperie (cinéma, littérature, arts vivants, jeu vidéo) et dans celui des techniques de persuasion, de simulation ou de manipulation intervenant dans l’espace informationnel (réseaux sociaux, bots politiques, fake news, deep fakes, dispositifs d’intelligence artificielle, théories de la conspiration). Les deux champs d’investigation suscitent des imaginaires sociaux qu’il s’agira d’étudier en les mettant en relation pour mieux en exposer les rouages.',NULL,1,NULL),
(79484,14930,2097,13419,'resource',NULL,NULL,NULL,1,NULL),
(79485,14930,2097,13498,'resource',NULL,NULL,NULL,1,NULL),
(79486,14930,2097,15043,'resource',NULL,NULL,NULL,1,NULL),
(79499,14930,2097,13519,'resource',NULL,NULL,NULL,1,NULL),
(79500,14930,2097,13418,'resource',NULL,NULL,NULL,1,NULL),
(79501,14931,1,NULL,'literal','','Dévoilement du site Web ARCANES + Lancement de la version numérique de l\'ouvrage « Le livre en contexte numérique. Un défi de design » sous la direction de Renée Bourassa.',NULL,1,NULL),
(79502,14931,386,14436,'resource',NULL,NULL,NULL,1,NULL),
(79503,14931,7,NULL,'numeric:timestamp',NULL,'2021-10-08',NULL,1,NULL),
(79504,14931,19,NULL,'literal','','« Cette publication porte sur le livre en contexte numérique que les pratiques innovantes du design reconfigurent. Le livre prend sa place dans un écosystème de production et de diffusion des savoirs qu’il partage avec d’autres dispositifs éditoriaux, dont les variantes sont devenues proliférantes. La problématique centrale sur laquelle les auteurs de cet ouvrage se penchent est de comprendre comment le livre se transforme dans son écosystème numérique actuel, en nous renvoyant à deux questions transversales : qu’est-ce qu’un livre ? En quoi constitue-t-il un défi de design en contexte numérique ? Figure emblématique des pratiques culturelles transformées par les affordances et les usages du numérique, à la fois investi d’une charge symbolique héritée de sa longue histoire et vecteur des humanités numériques, le livre est envisagé dans ses champs d’expérience, ses usages et ses représentations.Cet ouvrage gravite autour de la rencontre entre, d’un côté, les études littéraires et les sciences humaines et de l’autre, les méthodes de design numérique. À travers la figure du livre, noyau central de la réflexion, cette perspective nous permet de repenser d’un point de vue théorique et pratique les modalités de création et de circulation des savoirs et des imaginaires portés par la figure du livre dans l’écosystème socionumérique, tant en fonction de sa matérialité que de son hybridité. La part d’une pensée du design en tant que médiateur devient incontournable, car celui-ci prend en charge les processus d’éditorialisation dans une visée d’expérience. entre sa forme profondément ancrée dans la culture matérielle et ses multiples incarnations au sein de l’écosystème socionumériques dans lequel il s’inscrit. »',NULL,1,NULL),
(79505,14931,555,16737,'resource',NULL,NULL,NULL,1,NULL),
(79506,14932,1,NULL,'literal','','Conférence d\'ouverture du Colloque international H2PTM 2021 - Information : Enjeux et technologie',NULL,1,NULL),
(79507,14932,386,14436,'resource',NULL,NULL,NULL,1,NULL),
(79508,14932,7,NULL,'numeric:timestamp',NULL,'2021-10-13',NULL,1,NULL),
(79509,14932,19,NULL,'literal','','L\'écosystème socionumérique actuel est marqué par la prolifération des puissances du faux, notamment les fake news et les deep fakes, qui atténuent considérablement notre capacité à détecter les manifestations de tromperie. Ces phénomènes ne sont pas nouveaux.  Des pratiques artistiques, que nous qualifions d\'« arts trompeurs », jouent depuis longtemps sur les ressorts de l\'illusion, qu\'elle soit occultée ou affichée, afin de divertir. Mais la situation actuelle révèle une rupture majeure : le système reposant sur les « régimes d\'authenticité » qui fournissait des repères partageables, tout en assurant l\'évolution de ce qu\'on considérait « vrai », n\'est plus opérant. L\'efficacité et l\'abondance des stratégies de tromperie dans l\'espace informationnel vont jusqu\'à mettre nos démocraties à risque. Le développement d\'une nouvelle littéracie informationnelle s\'impose donc comme une urgence.\n\nLe groupe de recherche ARCANES participe à la 16e édition du colloque international H2PTM 2021 « Information : Enjeux et nouveaux défis » qui se tiendra du 13 au 15 octobre 2021 au Campus Condorcet-Aubervilliers / Université Paris 8 (France).',NULL,1,NULL),
(79510,14932,339,NULL,'literal','','La conférence aborde divers aspects liés à la tromperie, à l\'illusion et à la médiation culturelle. Elle explore l\'évolution de ces concepts à travers l\'histoire, en mettant l\'accent sur les techniques utilisées dans les arts du spectacle, notamment la magie et le cinéma. La présentation examine également l\'impact des technologies modernes, telles que l\'intelligence artificielle et les images de synthèse, sur notre perception de la réalité et sur les pratiques de médiation culturelle contemporaines. Elle aborde la question de l\'authenticité dans un contexte médiatique contemporain marqué par la prolifération de la désinformation et de la manipulation, et met en lumière les défis posés par les technologies numériques et les nouveaux régimes d\'autorité qui émergent dans cet environnement. L\'accent est mis sur la remise en cause des notions traditionnelles d\'autorité et de vérité, ainsi que sur l\'importance de la crédibilité de l\'information et du développement du sens critique pour contrer les abus. Le rôle des algorithmes et de l\'intelligence artificielle dans la propagation de la désinformation est également examiné, tout comme les défis posés par la falsification des données et la manipulation des médias numériques. Finalement, la conférence aborde les implications des technologies de génération de contenu automatique, telles que les générateurs automatiques de texte, dans la manipulation de l\'opinion publique et la propagation de la désinformation. Elle souligne les risques liés à l\'utilisation de ces technologies pour influencer les élections, réécrire l\'histoire, manipuler l\'opinion publique et créer',NULL,1,NULL),
