(79717,14938,1,NULL,'literal','','Images et séries culturelles de l’ivresse. Frictions diégétiques et musicalités circulaires',NULL,1,NULL),
(79718,14938,386,14449,'resource',NULL,NULL,NULL,1,NULL),
(79719,14938,7,NULL,'numeric:timestamp',NULL,'2021-11-05',NULL,1,NULL),
(79720,14938,19,NULL,'literal','','Cette intervention propose de suivre les régimes de représentation de cette fiction par disjonction que constitue l’ivresse (dans les images de lanterne magique, de BD, de cinéma (Chaplin-Murnau), jusqu’aux pubs Smirnoff… Soit une sorte de mini archéologie visuelle de l’ivresse.',NULL,1,NULL),
(79721,14938,339,NULL,'literal','','Le conférencier aborde le sujet de l\'ivresse à travers une perspective d\'archéologue des médias et des systèmes d\'expression. Il explore comment les représentations visuelles de l\'ivresse traversent les siècles, en mettant en évidence la porosité, la confusion et la suspension présentes dans ces représentations. Il discute également de l\'écologie perturbée de l\'ivresse et de son expression à travers différents médias, notamment la bande dessinée, et il examine les effets internes et externes de l\'ivresse, soulignant la circularité présente dans les représentations et son lien avec les formes circulaires dans l\'art visuel. L\'analyse du conférencier explore les aspects visuels et rhétoriques de cette représentation, mettant en lumière des concepts tels que la métaphore, la métonymie et la circularité. L\'ivresse est examinée comme une métaphore complexe, révélant des couches de sens à travers des jeux optiques et narratifs.',NULL,1,NULL),
