(79830,14943,1,NULL,'literal',NULL,'Illusion et manipulation des sens : effets de présence et interpellation des personnages virtuels',NULL,1,NULL),
(79831,14943,386,14431,'resource',NULL,NULL,NULL,1,NULL),
(79832,14943,7,NULL,'numeric:timestamp',NULL,'2022-09-23',NULL,1,NULL),
(79833,14943,19,NULL,'literal',NULL,'Dans le domaine des jeux vidéo, les techniques d’intelligence artificielle ont notamment bénéficié au développement et au perfectionnement du comportement et de l’autonomie des personnages dits « non-joueurs » (non-player character, abrégé NPC). Considérés comme des agents rationnels capables de prendre des décisions et d’agir en fonction des informations dont ils disposent et des buts pour lesquels ils ont été programmés, les PNJ cherchent à simuler l’intelligence humaine pour donner de la crédibilité à l’expérience vidéoludique et renforcer le sentiment d’immersion. Ultimement, il s’agit de donner aux joueurs et aux joueuses l’illusion qu’ils ont moins affaire à des algorithmes qu’à des personnages vivants, animés par des désirs et des buts qui leur sont propres. Cette présentation propose de revenir sur certaines techniques utilisées dans les jeux vidéo pour donner aux PNJ les capacités de manipuler et tromper les sens. Nous verrons également comment certaines de ces techniques et stratégies de tromperie finissent par s’étendre à d’autres secteurs de monde social.',NULL,1,NULL),
(79835,14943,339,NULL,'literal',NULL,'La conférence porte sur une présentation abordant les techniques et stratégies utilisées dans les jeux vidéo pour donner aux personnages non-joueurs des capacités de manipulation et de tromper les sens. Fabien Richert commence par définir certains concepts liés à l\'intelligence artificielle dans les jeux vidéo, puis explore les différents embrayeurs utilisés pour créer l\'effet de présence, notamment la similitude, le dédoublement et la mise en scène de l\'absence. Il illustre ses propos en se basant sur deux études de cas : Red Dead Redemption 2 et The Last of Us 2. Il présente une analyse des mécanismes d\'immersion et d\'interpellation dans les jeux vidéo, en mettant en avant l\'effet de présence, et discute de la mise en scène de l\'absence, de la trace et de l\'interpellation dans différents contextes vidéoludiques. Il évoque également l\'utilisation de ces mécanismes dans des technologies telles que les assistants virtuels intelligents et les deepfakes.',NULL,1,NULL),
(79836,14943,2097,15026,'resource',NULL,NULL,NULL,1,NULL),
(79837,14944,1,NULL,'literal',NULL,'Illusion et manipulation des sens : effets de présence et interpellation des personnages virtuels',NULL,1,NULL),
(79838,14944,386,14436,'resource',NULL,NULL,NULL,1,NULL),
(79839,14944,7,NULL,'numeric:timestamp',NULL,'2022-09-23',NULL,1,NULL),
(79840,14944,19,NULL,'literal',NULL,'Dans le domaine des jeux vidéo, les techniques d’intelligence artificielle ont notamment bénéficié au développement et au perfectionnement du comportement et de l’autonomie des personnages dits « non-joueurs » (non-player character, abrégé NPC). Considérés comme des agents rationnels capables de prendre des décisions et d’agir en fonction des informations dont ils disposent et des buts pour lesquels ils ont été programmés, les PNJ cherchent à simuler l’intelligence humaine pour donner de la crédibilité à l’expérience vidéoludique et renforcer le sentiment d’immersion. Ultimement, il s’agit de donner aux joueurs et aux joueuses l’illusion qu’ils ont moins affaire à des algorithmes qu’à des personnages vivants, animés par des désirs et des buts qui leur sont propres. Cette présentation propose de revenir sur certaines techniques utilisées dans les jeux vidéo pour donner aux PNJ les capacités de manipuler et tromper les sens. Nous verrons également comment certaines de ces techniques et stratégies de tromperie finissent par s’étendre à d’autres secteurs de monde social.',NULL,1,NULL),
(79842,14944,339,NULL,'literal',NULL,'La conférence aborde le thème des figures de l\'automate dans les médias contemporains, notamment dans le cinéma et les jeux vidéo, en explorant les concepts de simulacres, de figures de synthèse, de vie artificielle et d\'intelligence artificielle. Renée Bourassa examine l\'évolution de l\'automate depuis l\'Antiquité jusqu\'à nos jours, en mettant en évidence son lien avec les questions philosophiques sur le corps et l\'esprit, ainsi que les implications anthropologiques et sociétales. Elle analyse également les techniques de création des personnages de synthèse et les défis liés à la simulation des émotions humaines, en se concentrant sur les expressions faciales. Cette conférence porte sur la difficulté de simuler des émotions de manière crédible dans les représentations artificielles, que ce soit dans le domaine du cinéma, des jeux vidéo ou de la robotique. L\'objectif est de créer des personnages synthétiques capables de susciter l\'empathie et de sembler authentiques. Cependant, malgré les avancées technologiques, les écarts entre les représentations synthétiques et les êtres humains restent perceptibles, ce qui peut entraîner un sentiment de malaise chez les spectateurs. Cette difficulté soulève des questions philosophiques sur l\'intentionnalité, la conscience et la frontière entre l\'être vivant et l\'automate, notamment dans le contexte du transhumanisme.',NULL,1,NULL),
(79843,14944,2097,15026,'resource',NULL,NULL,NULL,1,NULL),
(79844,14945,1,NULL,'literal','','Pour des environnements numériques contre-intuitifs, complexes et hétérogènes. La littératie numérique à l’épreuve des GAFAM',NULL,1,NULL),
(79845,14945,386,14440,'resource',NULL,NULL,NULL,1,NULL),
(79846,14945,7,NULL,'numeric:timestamp',NULL,'2022-10-07',NULL,1,NULL),
(79847,14945,19,NULL,'literal','','Les environnements numériques sont désormais dominés par une poignée d’entreprises privées qui nous promettent des technologies intuitives, simples et neutres, qui « résolvent » nos problèmes sans que nous devions nous poser trop de questions et surtout sans que nous devions trop penser. Cette rhétorique est à la base d’une incompétence numérique croissante: nous dépendons des GAFAM, les GAFAM pensent à notre place. Une littératie numérique véritable demande une mise en question radicale de cette rhétorique: il faut rechercher des environnements contre-intuitifs, complexes et hétérogènes.',NULL,1,NULL),
(79849,14945,339,NULL,'literal','','La conférence met en lumière la façon dont les environnements numériques, tels que Zoom, Google et Word, conditionnent notre pensée et notre comportement. Marcello Vitali-Rosati critique la rhétorique des GAFAM, soulignant que nous adhérons aveuglément à leurs valeurs et que cela entrave notre littératie numérique. Il aborde deux aspects principaux : l\'immatérialité et l\'intuitivité. Il explique que ces outils sont présentés comme simples, performants et intuitifs, mais en réalité, ils façonnent notre façon de penser de manière univoque. Il souligne également le danger de cette rhétorique, qui cache l\'influence et les valeurs des environnements techniques. Il exprime sa frustration quant à l\'approche de la littératie numérique à l\'école primaire, notamment l\'utilisation des iPad, qui, selon lui, ne favorise pas le développement de la pensée critique mais plutôt l\'assujettissement à un modèle unique. Il aborde également la nécessité de considérer les dysfonctionnements comme une voie vers la pensée critique et propose trois types d\'outils dysfonctionnels : les outils cassés, les outils complexes et les outils inutiles. Pour illustrer son point de vue, il utilise des exemples de dysfonctionnements dans le contexte philosophique et conclut en affirmant que les sciences humaines devraient être \"un bug\" pour provoquer le changement.',NULL,1,NULL),
(79850,14945,2097,15056,'resource',NULL,NULL,NULL,1,NULL),
(79851,14946,1,NULL,'literal','','Fabriques en commun et protocoles ouverts : vers une réappropriation de l’écosystème des connaissances',NULL,1,NULL),
(79852,14946,386,14453,'resource',NULL,NULL,NULL,1,NULL),
(79853,14946,7,NULL,'numeric:timestamp',NULL,'2022-10-07',NULL,1,NULL),
(79854,14946,19,NULL,'literal','','Pour cette intervention, je propose d’explorer la question de la désinformation au prisme de la notion de littératie numérique en considérant que la désinformation est d’abord le résultat d’une certaine déprise de notre écosystème d’information. Il s’agira tout d’abord de saisir les différentes facettes de la littératie numérique, en lien avec les différentes couches de l’écriture numérique, puis de l’articuler avec la notion de protocole pour voir comment certains protocoles de production de connaissances nous permettent de collectivement reprendre la main sur la fabrique des savoirs. Nous tenterons ainsi de dessiner quelques pistes pour appliquer ce que Louise Merzeau appelait « la maîtrise de la déprise ».',NULL,1,NULL),
(79856,14946,339,NULL,'literal','','La conférence aborde la question de la littératie numérique à travers une anecdote sur la création d\'une page Wikipedia et les difficultés rencontrées, notamment liées à la méconnaissance des protocoles et des règles de la plateforme. Nicolas Sauret souligne l\'importance de comprendre les différentes couches de l\'écriture numérique et propose différentes perspectives, notamment sociétale, économique et philosophique, pour appréhender cette notion. Il explore l\'évolution des écritures numériques, mettant en avant l\'importance des protocoles et des licences copyleft dans différents domaines tels que le logiciel, la culture et le juridique, et il aborde également les changements induits par le numérique dans la pratique scientifique, notamment en sciences humaines, remettant en question les paradigmes de vérité et les protocoles éditoriaux traditionnels. L\'incident de Wikipédia est utilisé comme exemple pour illustrer les enjeux de l\'écriture collective versus la rédaction individuelle, mettant en lumière la nécessité de repenser les modalités de production et de circulation des connaissances.',NULL,1,NULL),
(79857,14946,2097,15056,'resource',NULL,NULL,NULL,1,NULL),
(79858,14947,1,NULL,'literal','','Accès, exploitation et réutilisation des données patrimoniales de la BNF',NULL,1,NULL),
(79859,14947,386,14454,'resource',NULL,NULL,NULL,1,NULL),
(79860,14947,7,NULL,'numeric:timestamp',NULL,'2022-10-21',NULL,1,NULL),
(79861,14947,19,NULL,'literal','','Les collections numériques de la BnF représentent une masse considérable de données (plus de six pétaoctets), d’une grande diversité, tant par leur forme que par leur contenu : documents numérisés dans Gallica et Gallica intramuros, métadonnées descriptives, jeux vidéo, CD et DVD, ou documents nés numériques comme les archives du web, les logs de connexion, etc. L’augmentation exponentielle de ces ressources a ouvert de nouvelles pistes de recherche et fait émerger des problématiques d’exploitation des données par les chercheurs. À la BnF, la question de l’ouverture et l’accès aux données est complexe car elle dépend du type de données et du cadre juridique dans lequel celles-ci s’inscrivent. Quelle est la singularité des données patrimoniales de la BnF ? Quelles en sont les modalités d’accès, d’exploitation et de réutilisation ? Quels services et outils la BnF met-elle à disposition des chercheurs dans son DataLab pour développer les usages sur ses collections numériques ?',NULL,1,NULL),
(79863,14947,339,NULL,'literal','','Arnaud Laborderie travaille à la BNF et se concentre sur l\'exploitation des données de Gallica pour la recherche en humanités numériques. Il aborde les défis d\'accès, d\'exploitation et de réutilisation des données, notamment les collections numériques nationales de Gallica. Il discute des efforts pour rendre accessible une masse documentaire considérable et présente le Data Lab de la BNF, un lieu dédié à l\'exploitation des collections numériques et à l\'accompagnement des nouveaux usages de la recherche. La présentation concerne la récupération de données dans le contexte des bibliothèques numériques. Elle aborde les différents entrepôts de données, les protocoles de récupération, les API disponibles, ainsi que les projets de recherche liés à l\'analyse des données et à la recommandation de contenus. Des technologies telles que le deep learning et le topic modeling sont également évoquées pour l\'analyse des textes. Enfin, il est question de l\'utilisation éthique des données d\'usage pour la recommandation de contenu sans identifier individuellement les utilisateurs.',NULL,1,NULL),
(79864,14947,937,14948,'resource',NULL,NULL,NULL,1,NULL),
(79865,14948,1,NULL,'literal','','Chaoticum Seminario : stimulations aléatoires de discussions scientifiques',NULL,1,NULL),
(79866,14948,386,14429,'resource',NULL,NULL,NULL,1,NULL),
(79867,14948,7,NULL,'numeric:timestamp',NULL,'2022-10-21',NULL,1,NULL),
(79868,14948,19,NULL,'literal','','Les scientifiques sont depuis longtemps outillées afin d’optimiser les observations servant de base aux faits analysés, par exemple avec le microscope, l’accélérateur de particules, les formulaires d’enquêtes en ligne ou la constitution automatique de corpus à partir des archives numérisées. Les outils qu’ils utilisent servent aussi à formaliser leurs discours pour faciliter leurs éditorialisations et leurs diffusions, par exemple avec un traitement de texte, des bases de données ou des plateformes Web. Le plus souvent, ces outils servent à satisfaire l’injonction mondiale de produire toujours plus afin de monter dans la hiérarchie des classements scientifiques et des institutions de légitimation. Les productions scientifiques sont désormais soumises aux règles de la « Grande distribution » qui transforment le chercheur en prolétaire alimentant une méga-machine productrice de connaissances. Le prototype que nous présentons dans ce séminaire propose un autre modèle de production scientifique qui privilégie la stimulation des discussions entre humains à partir d’un processus aléatoire d’exploration des connaissances.',NULL,1,NULL),
(79870,14948,339,NULL,'literal','','Samuel Szoniecky présente une expérimentation sur les nouvelles formes d\'écriture et de discours scientifique, utilisant un générateur de conférences alimenté par des sources diverses. L\'expérience est décrite comme une exploration de l\'abondance des données disponibles et des nouveaux modes de communication scientifique. Malgré quelques difficultés techniques et déviations humoristiques, Samuel Szoniecky cherche à stimuler la réflexion sur la manière dont ces outils peuvent être utilisés dans la recherche et l\'enseignement. Il présente un projet où sont utilisées différentes sources telles que des conférences, des notes de Zotero, des vidéos de séminaires, des programmes de recherche, et des bases de données pour créer un système automatisé d\'extraction de citations et de fragments de textes. L\'objectif est de fournir un résumé succinct des séminaires Arcanes, en évitant l\'exhaustivité et en favorisant une approche fragmentaire pour stimuler de nouvelles idées.',NULL,1,NULL),
(79871,14948,2097,15038,'resource',NULL,NULL,NULL,1,NULL),
(79872,14949,1,NULL,'literal','','Montrer l’impossible : le truc entre scène et écran',NULL,1,NULL),
(79873,14949,386,14455,'resource',NULL,NULL,NULL,1,NULL),
(79874,14949,7,NULL,'literal','','2022-10-28',NULL,1,NULL),
(79875,14949,7,NULL,'numeric:timestamp',NULL,'2022-10-28',NULL,1,NULL),
(79877,14949,19,NULL,'literal','','Dans son célèbre article « Les vues cinématographiques » de 1907, Georges Méliès déclarait que dorénavant, grâce aux trucages « il est aujourd’hui possible de réaliser les choses les plus impossibles et les plus invraisemblables ». Et c’est ce que Méliès a tenté de prouver dans de nombreux films. Dans cette intervention nous regarderons, pour commencer, de quelle manière le truc et le trucage participent aux « puissances du faux » et, en même temps, cherchent à couper les liens qui les rattachent au faux. Ensuite, nous essayerons de proposer quelque chose comme une « anatomie » du truc pour mieux comprendre comment il fonctionne et comment il parvient à nous montrer ce dont nous savons qu’il ne peut pas exister.',NULL,1,NULL),
(79878,14949,339,NULL,'literal','','La conférence explore l\'histoire des films truqués, mettant en lumière les différentes perspectives sur ces productions cinématographiques. Frank Kessler commence par discuter d\'un article de 192 sur les \"fake cinématographes\", présentant des films qui pourraient devenir populaires en montrant des événements impossibles. Ensuite, il évoque l\'investissement de temps et de savoir-faire nécessaire pour créer ces films, ainsi que les différences entre les \"trick films\" et les \"fake films\". Il examine également les liens entre les films truqués et les spectacles de magie, soulignant que le public est conscient des manipulations mais est fasciné par les effets visuels impossibles. La conférence explore ensuite les techniques utilisées par les magiciens et cinéastes pour tromper le public. En citant Robert Houdin et Alfred Binet, Frank Kessler met en lumière l\'importance d\'égarer l\'esprit des spectateurs. Les exemples incluent l\'utilisation de mécaniques, d\'artifices scientifiques et de techniques visuelles telles que les coulures de Méliès et la continuité apparente. Des exemples de scènes de théâtre et de cinéma, comme celle de \"Le Roi Carotte\" et \"Cendrillon\" de Méliès, illustrent la façon dont la continuité spatiale suggère une continuité temporelle, défiant ainsi la perception du spectateur.',NULL,1,NULL),
(79879,14950,1,NULL,'literal','','Le remploi de témoignages filmés dans des films documentaires historiques. Le cas de The U.S. and the Holocaust (Ken Burns, Lynn Novick et Sarah Botstein, 2022).',NULL,1,NULL),
(79880,14950,386,14481,'resource',NULL,NULL,NULL,1,NULL),
(79881,14950,7,NULL,'numeric:timestamp',NULL,'2022-10-28',NULL,1,NULL),
(79882,14950,19,NULL,'literal','','À travers l’étude du cas The U.S. and the Holocaust (Ken Burns, Lynn Novick et Sarah Botstein, 2022), cette communication porte sur l’émergence de l’usage d’extraits de témoignages filmés archivés dans des documentaires historiques. Cela conduit notamment à se demander de quelles manières de tels extraits sont montés. Dit autrement: est-ce que leur usage est assumé par l’équipe du film? Est-ce qu’ils sont contextualisés par l’exposition de leurs conditions de production? Ou, est-ce que, au contraire, cela relève du non-dit? On peut alors parler de décontextualisation, au sens où, les spectateurs et spectatrices ne reçoivent aucune information sur la manière dont ces entretiens ont, originellement, été menés. Enfin, est-ce que cet usage devient un enjeu du documentaire? Il serait alors possible de parler d’une mise en tension entre tendance à décontextualiser et processus de recontextualisation. L’étude de ces gestes conduit à prendre conscience des conséquences de cet usage sur l’écriture cinématographique de l’histoire proposée. Pour cette communication, je vais surtout insister sur l’usage d’une séquence issue d’un entretien tourné à la fin des années 1970 avec John Pehle par Claude Lanzmann et son équipe pour Shoah (1985).',NULL,1,NULL),
(79884,14950,339,NULL,'literal','','La conférence présente une discussion sur l\'utilisation des témoignages filmés et des archives visuelles dans les documentaires historiques, en mettant l\'accent sur le film « Les États-Unis et l\'Holocauste » réalisé par Ken Burns. Rémy Besson examine différents types de documentaires, notamment ceux qui utilisent des images archivées et ceux qui se concentrent sur les témoignages filmés. Il aborde également les questions de contextualisation, de décontextualisation et de recontextualisation des témoignages. Le film en question retrace le génocide des Juifs d\'Europe et les actions des responsables politiques américains pendant cette période. Il présente des entretiens avec des survivants, des historiens et des chercheurs, ainsi que des images d\'archives associées à des mouvements de caméra caractéristiques de Ken Burns. La conférence porte également sur l\'analyse d\'un extrait documentaire où des images d\'archives sont utilisées pour donner la parole à des acteurs de l\'histoire. Rémy Besson discute de la manière dont ces séquences archivées sont utilisées sans contexte clair, ce qui crée une décontextualisation trompeuse pour le spectateur. Il met en lumière trois points principaux : le déplacement du statut des archives vers un usage testimonial, la décontextualisation des documents d\'archives et le montage de la piste sonore pour correspondre à ce que l\'équipe du film veut faire entendre. Il souligne la complexité de cette pratique émergente et ses implications sur l\'écriture cinématographique de l\'histoire dans les documentaires.',NULL,1,NULL),
(79885,14950,2097,15026,'resource',NULL,NULL,NULL,1,NULL),
(79886,14951,1,NULL,'literal','','Stratégies du faux et nostalgie réactionnaire : la vidéo de la campagne électorale d’Éric Zemmour',NULL,1,NULL),
(79887,14951,386,14456,'resource',NULL,NULL,NULL,1,NULL),
(79888,14951,7,NULL,'numeric:timestamp',NULL,'2022-11-11',NULL,1,NULL),
(79889,14951,19,NULL,'literal','','Ancré dans les études critiques sur la nostalgie et la mémoire, la présente recherche analyse la manière dont le passé est soumis au risque d’une fictionnalisation mue par un désir d’idéalisation de l’histoire sur la scène politique. Nous étudions en particulier la mise en place d’un nationalisme nostalgique dans la vidéo d’annonce de candidature aux élections présidentielles en France d’Éric Zemmour, publiée sur YouTube le 30 novembre 2021. Notre intervention déconstruit la mise en scène d’un passé fantasmé à travers le récit imaginaire d’un âge d’or perdu qui ne semble exister que pour souligner son propre déclin. Cette nostalgie réactionnaire repose par ailleurs sur la construction d’une méta-mémoire portée par une obsession identitaire. Les abus de la mémoire et la représentation chaotisée du présent sont des leviers pour arrimer la nostalgie avec la xénophobie et le rejet de l’altérité.',NULL,1,NULL),
(79891,14951,339,NULL,'literal','','La conférence explore la complexité de la nostalgie dans le discours politique contemporain, en se concentrant sur la vidéo de campagne présidentielle d\'Éric Zemmour en 2021. Les chercheurs examinent comment la nostalgie est exploitée pour manipuler la mémoire collective, en soulignant les processus de marchandisation et de politisation du passé. Cette approche critique met en lumière la manière dont les récits nostalgiques sont utilisés pour idéaliser un passé glorieux, tout en dramatisant le présent, créant ainsi une nostalgie réactionnaire. Le discours de Zemmour, accompagné d\'images d\'archives et d\'une bande sonore de Beethoven, illustre comment la mémoire est esthétisée et décontextualisée pour servir des fins politiques. Les chercheurs soulignent que cette instrumentalisation du passé n\'est ni nouvelle ni exceptionnelle, mais s\'inscrit dans une tradition de nationalismes nostalgiques. L\'analyse met en avant les risques que ces récits idéalisés posent, notamment en termes d\'adhésion publique à des visions simplistes et excluantes de l\'identité nationale. En déconstruisant les mécanismes audiovisuels et narratifs de la vidéo, la conférence révèle comment la nostalgie peut être arrimée à la haine et au rejet de l\'altérité, exacerbant ainsi les tensions sociopolitiques contemporaines. Cette étude s\'inscrit dans un réseau international de recherche sur la nostalgie, visant à comprendre et à critiquer ces dynamiques mémorielles complexes.',NULL,1,NULL),
(79892,14951,86,20885,'resource',NULL,NULL,NULL,1,NULL),
(79893,14952,1,NULL,'literal','','Stratégies du faux et nostalgie réactionnaire : la vidéo de la campagne électorale d’Éric Zemmour',NULL,1,NULL),
