(79961,14962,7,NULL,'numeric:timestamp',NULL,'2023-11-29',NULL,1,NULL),
(79963,14962,339,NULL,'literal',NULL,'La conférence aborde les défis contemporains de l\'éducation critique aux médias et à l\'information, illustrant les effets pernicieux des médias modernes et des réseaux sociaux sur la perception de la réalité. À travers une mission parlementaire en France, l\'accent est mis sur l\'importance d\'une éducation critique face à la prolifération des chaînes d\'information continue, qui brouillent les lignes entre experts et lobbyistes, et favorisent une économie de l\'attention basée sur le sensationnalisme. Les réseaux sociaux exacerbent ces problématiques en renforçant les biais cognitifs, créant des bulles de filtre qui isolent les individus dans des réalités parallèles. Les algorithmes, motivés par des intérêts commerciaux, manipulent l\'information pour maximiser l\'engagement, compromettant ainsi la démocratie. L\'exemple de Cambridge Analytica illustre comment des données personnelles sont exploitées pour influencer des élections, tandis que la manipulation des réseaux sociaux en France montre que ces pratiques ne sont pas limitées aux États-Unis. Les conséquences incluent une défiance envers les institutions politiques, une perception biaisée de la vérité scientifique, et une exposition accrue aux arnaques et à la cybercriminalité. Enfin, même les espaces de confiance, censés préserver le patrimoine culturel et la mémoire collective, sont remis en question par la prolifération de contenus numériques altérés. Cette analyse souligne l\'urgence d\'une éducation aux médias robuste pour naviguer dans un paysage informationnel de plus en plus complexe et fragmenté.',NULL,1,NULL),
(79964,14963,1,NULL,'literal',NULL,'Être ou ne pas être trompé : interpréter les pouvoirs des IA génératives',NULL,1,NULL),
