(79994,14969,1,NULL,'literal',NULL,'Puissances du faux, faiblesses du vrai : illusion,\ntromperie et intelligence artificielle',NULL,1,NULL),
(79995,14969,386,14436,'resource',NULL,NULL,NULL,1,NULL),
(79996,14969,7,NULL,'numeric:timestamp',NULL,'2023-11-29',NULL,1,NULL),
(79998,14969,339,NULL,'literal',NULL,'La conférence explore les dynamiques de médiation culturelle et technologique à travers le prisme des arts trompeurs, en mettant l\'accent sur l\'intégration des deepfakes et de l\'intelligence artificielle dans les pratiques artistiques contemporaines. Le groupe de recherche ARCAN, cofondé par Jean-Marc Larue, s\'intéresse à la sémiotique et à l\'intermédialité des puissances du faux, examinant comment ces phénomènes historiques se manifestent aujourd\'hui dans les écosystèmes sociolumériques. Les deepfakes, en particulier, sont analysés pour leur capacité à tromper les sens et à remettre en question les frontières entre le vrai et le faux. L\'utilisation de ces technologies soulève des questions éthiques et légales, notamment en ce qui concerne le droit à l\'image et la manipulation des archives historiques. La notion de magicalité est également abordée, décrivant l\'opacité des médiations techniques qui rendent les effets magiques indiscernables de la réalité. En examinant des cas concrets, tels que la résurrection algorithmique d\'acteurs décédés et la création de récits uchroniques, la conférence souligne la rapidité avec laquelle les technologies de l\'IA évoluent, amplifiant les crises de vérité et de confiance dans nos sociétés. Enfin, la manipulation des archives historiques par le biais des deepfakes est présentée comme un défi majeur, posant la question de l\'intégrité et de la véracité dans la transmission du savoir historique.',NULL,1,NULL),
(79999,14970,1,NULL,'literal',NULL,'La mécanique du faux à l’œuvre\ndans le spectacle d’illusionnisme, l’art magique et sa réception spectatorielle',NULL,1,NULL),
