(84500,15682,1,NULL,'literal',NULL,'Récits numériques et intelligence artificielle',NULL,1,NULL),
(84501,15682,386,15522,'resource',NULL,NULL,NULL,1,NULL),
(84502,15682,7,NULL,'numeric:timestamp',NULL,'2024-10-04',NULL,1,NULL),
(84503,15682,19,NULL,'literal',NULL,'Dans cette présentation, je replacerai les récits générés avec des IA plus largement dans le cadre des récits numériques, notamment interactifs (hypertextuels, cinétiques, participatifs). Je m’appuierai ensuite sur des exemples de récits co-écrits avec des IA et je pointerai certaines questions que ces récits posent. J’envisagerai enfin quelques perspectives.',NULL,1,NULL),
(84522,15682,2097,15026,'resource',NULL,NULL,NULL,1,NULL),
(84527,15682,2097,15038,'resource',NULL,NULL,NULL,1,NULL),
(84528,15693,1,NULL,'literal',NULL,'Dimensions narratives de l’IA générative : entre créativité, auctorialité et nouveaux matérialisme',NULL,1,NULL),
(84529,15693,386,14436,'resource',NULL,NULL,NULL,1,NULL),
(84530,15693,7,NULL,'numeric:timestamp',NULL,'2024-10-04',NULL,1,NULL),
(84531,15693,19,NULL,'literal',NULL,'Cette intervention se penche sur les dispositifs narratifs issus de l’IA générative, qui investissent les pratiques créatives et l’écosystème socionumérique. La communication traite  des relations existantes entre les puissances du faux et les dispositifs mis en œuvres par l’IA. En s’appuyant sur des exemples issus de la littérature et du cinéma, comprenant les figures de l’automate, des images générées par Dall-E ou encore, des Deepfakes,  la réflexion pose un regard critique sur les pratiques narratives de l’intelligence artificielle  générative. Elle problématise les concepts de créativité, d’auctorialité et d’authenticité, tout en relevant les changements opérés dans les processus de création artistique. Sont abordées les dynamiques relationnelles entre les humains et les non-humains, vus comme des assemblages, qui posent les questions centrales suivantes : Qu’est-ce que la créativité? La machine est-elle capable d’invention , d’innovation et d’originalité, en dépassant les jeux de l’imitation des créations humaines? Quel est le statut de l’auteur à l’ère de l’IA générative? Comment penser l’authenticité en relation avec les produits de l’IA générative? Des perspectives s’ouvrent au prisme des courants de pensée philosophique des nouveaux matérialismes et du transhumanisme, portant l’attention sur la matérialité du monde. De plus, l’IA générative pose des enjeux sociaux, légaux, éthiques et environnementaux considérables, qui seront discutés.',NULL,1,NULL),
