(84814,15741,1,NULL,'literal',NULL,'La narration générative entre IA symbolique et connexionniste : une expérience transnationale',NULL,1,NULL),
(84815,15741,386,14429,'resource',NULL,NULL,NULL,1,NULL),
(84816,15741,386,15735,'resource',NULL,NULL,NULL,1,NULL),
(84817,15741,7,NULL,'numeric:timestamp',NULL,'2024-10-11',NULL,1,NULL),
(84818,15741,19,NULL,'literal',NULL,'Dans cette présentation, nous partageons nos méthodes pour initier les étudiants à la narration générative et à d’autres formes de littérature numérique, alors qu’ils se préparent à travailler en équipes transnationales pour créer leurs propres narrations génératives en utilisant la base de données Omeka S, ComfyUI, Javascript, et le récent Large Language Model (LLM) AI, parmi d’autres outils. Laura Shackelford met en lumière certaines de ses propres recherches et approches en matière de narration générative et de pratiques littéraires numériques, dans la mesure où elles éclairent l’atelier de création numérique transnationale qu\'elle co-enseigne avec Samuel Szoniecky, et où elles guident ses futures recherches sur la narration dans le contexte de l’IA.',NULL,1,NULL),
