(84853,15748,1,NULL,'literal',NULL,'IA et IA : intelligence artificielle et invention architectonique',NULL,1,NULL),
(84854,15748,386,15746,'resource',NULL,NULL,NULL,1,NULL),
(84855,15748,7,NULL,'numeric:timestamp',NULL,'2024-10-18',NULL,1,NULL),
(84856,15748,19,NULL,'literal',NULL,'Cet exposé abordera la créativité à travers l’invention et l’imitation en architecture. Il s’interrogera notamment sur la façon dont l’intelligence artificielle articule un monde existant et sur les aspects de l’architecture qui solliciteront davantage l’intelligence humaine. L’IA permet de découvrir des stabilités et des récurrences d’un monde déjà en communication, en devinant le code de son recouvrement. Si l’architecture est l’art de jointer, de joindre, de réunir des choses disparates sans nécessairement de communes mesures, en quoi demeure-t-elle une manière d’inverser — avec grâce — la pesanteur ?',NULL,1,NULL),
(84857,15748,2097,15038,'resource',NULL,NULL,NULL,1,NULL),
(84858,15748,2097,15026,'resource',NULL,NULL,NULL,1,NULL),
(84861,15748,2097,13471,'resource',NULL,NULL,NULL,1,NULL),
(84862,15750,1,NULL,'literal',NULL,'Quelques intuitions autour des I.A. en architecture. Ce que nous disent les images générées',NULL,1,NULL),
(84863,15750,386,15742,'resource',NULL,NULL,NULL,1,NULL),
(84864,15750,7,NULL,'numeric:timestamp',NULL,'2024-10-18',NULL,1,NULL),
(84865,15750,19,NULL,'literal',NULL,'Les pratiques architecturales ont connu depuis quelques décennies plusieurs modifications, réajustements, transformations, plus ou moins tributaires des avancées technologiques. Les développements récents des réseaux antagonistes génératifs (GAN) ou encore plus récemment, ceux des modèles de diffusion (Midjourney, Dall-E2, Stable Diffusion 2), ont une fois de plus amené certains architectes à repenser leurs manières de faire ; encouragent à imaginer le projet différemment. Les capacités de ces moteurs à générer des images ont amené plusieurs architectes à explorer ces nouveaux procédés.\nPour cette intervention, j’analyserai deux technologies récentes (GAN et Modèles de diffusion) que plusieurs architectes ont employé de manière exploratoire.  L’attention se portera ensuite sur la manière dont ces architectes ont développé leurs investigations, afin d’obtenir des résultats en accord avec leurs attentes qui, comme nous le verrons, se modifient au fur et à mesure des expérimentations. La priorité ici n’est pas tant d’insister sur l’aspect inédit de ces modes de création, mais de mettre en lumière les choix instinctifs qui sont effectués dans ces processus employant l’intelligence artificielle.',NULL,1,NULL),
