(87435,16115,1,NULL,'literal','','The Computational Turn in Visual Political Communication Research',NULL,1,NULL),
(87436,16115,386,16116,'resource',NULL,NULL,NULL,1,NULL),
(87437,16115,7,NULL,'numeric:timestamp',NULL,'2023-10-12',NULL,1,NULL),
(87438,16115,19,NULL,'literal','','À une époque saturée de données visuelles, les techniques computationnelles sont devenues indispensables pour déchiffrer la communication politique et la désinformation à grande échelle. Cet exposé propose une revue concise de l’application de la vision par ordinateur dans la recherche contemporaine en communication politique visuelle. En tirant parti des outils d’apprentissage automatique, les chercheurs ont non seulement ouvert de nouvelles voies d’enquête sur divers sujets, allant des manifestations politiques à la propagande extrémiste, mais se sont également aventurés dans le domaine de la génération texte-image pour étudier le comportement politique. À mesure que ces techniques prennent de l’ampleur, les biais potentiels et les dimensions éthiques de la représentation des ensembles de données et des modèles génératifs deviennent encore plus évidents. Cette présentation vise à offrir un aperçu succinct du paysage actuel des méthodes computationnelle dans la recherche politique visuelle, abordant à la fois leurs capacités sans précédent et leurs défis inhérents.',NULL,1,NULL),
(87439,16115,2097,13471,'resource',NULL,NULL,NULL,1,NULL),
(87440,16115,2097,13445,'resource',NULL,NULL,NULL,1,NULL),
(87459,16123,1,NULL,'literal','','Artful Intrusions—A Hacker\'s Guide to Generative AI',NULL,1,NULL),
(87460,16123,386,16127,'resource',NULL,NULL,NULL,1,NULL),
(87461,16123,7,NULL,'numeric:timestamp',NULL,'2023-10-12',NULL,1,NULL),
(87462,16123,19,NULL,'literal','','Les modèles d’IA générative, bien que capables de produire des images convaincantes, occultent souvent leurs processus créatifs. Ils fournissent une forme illusoire de production médiatique, dans laquelle les mécanismes de formation sont obscurcis par des processus de boîte noire. Cette conférence présentera trois projets artistiques : Being Foiled, Teratome et Ghosts, tous nés d\'une approche hacker de l\'IA générative. Ces travaux sont le résultat de différentes interventions dans les phases d’entraînement et de génération de modèles d’IA, chacune offrant un aperçu unique du fonctionnement des processus génératifs à l’oeuvre.\n',NULL,1,NULL),
