(87483,16129,386,16130,'resource',NULL,NULL,NULL,1,NULL),
(87484,16129,7,NULL,'numeric:timestamp',NULL,'2023-10-12',NULL,1,NULL),
(87485,16129,19,NULL,'literal',NULL,'Journée d\'étude et ateliers \"Images trompeuses et modèles d\'intelligence artificielle\", Arcanes CRILCQ et Université de Montréal, Fresnoy - Studio national des arts contemporains, 12-13 octobre 2023. Organisation Gaëtan Robillard et Renée Bourassa.\nProgramme complet de la JE et ressources ateliers : https://github.com/robillardstudio/itmai\n\nSujets de la table ronde :\n- Differences between the new system and the old one ;\n- Drawing by hand to make data for deep learning ;\n- Changes in practice for Broad ;\n- Advice to students to start in deep learning AI.',NULL,1,NULL),
