(87531,16143,7,NULL,'numeric:timestamp',NULL,'2023-10-12',NULL,1,NULL),
(87532,16143,19,NULL,'literal',NULL,'Journée d\'étude et ateliers \"Images trompeuses et modèles d\'intelligence artificielle\", Arcanes CRILCQ et Université de Montréal, Fresnoy - Studio national des arts contemporains, 12-13 octobre 2023. Organisation Gaëtan Robillard et Renée Bourassa.\nProgramme complet de la JE et ressources ateliers : https://github.com/robillardstudio/itmai\n\nSujets de la table ronde :\n- Introduction ;\n- Vos deux approches scientifiques ont-elles un lien ? ;\n- Quelle place pour la science et la recherche dans un institut axé sur l\'image ? ;\n- Quelle place de l’IA dans vos travaux ? ;\n- L\'impact de la recherche scientifique sur l’art ;\n- L\'arrivée de l\'IA peut-elle modifier le système économique dans le domaine des arts ? ;\n- Questionnement sur la capacité de la machine à imiter le réel.',NULL,1,NULL),
