(87541,16144,1,NULL,'literal','','Table ronde - Fabien Richert, Constantine Boussalis, Gaëtan Robillard',NULL,1,NULL),
(87542,16144,386,14431,'resource',NULL,NULL,NULL,1,NULL),
(87543,16144,386,16116,'resource',NULL,NULL,NULL,1,NULL),
(87544,16144,386,14477,'resource',NULL,NULL,NULL,1,NULL),
(87545,16144,7,NULL,'numeric:timestamp',NULL,'2023-10-12',NULL,1,NULL),
(87546,16144,19,NULL,'literal','','Journée d\'étude et ateliers \"Images trompeuses et modèles d\'intelligence artificielle\", Arcanes CRILCQ et Université de Montréal, Fresnoy - Studio national des arts contemporains, 12-13 octobre 2023. Organisation Gaëtan Robillard et Renée Bourassa.\nProgramme complet de la JE et ressources ateliers : https://github.com/robillardstudio/itmai\n\nSujets de la table ronde :\n- What ethical problems are raised, and how can they be resolved ? ;\n- Are there any guidelines on how to use those agents ?',NULL,1,NULL),
(87547,16144,19,NULL,'uri','','Programme complet de la journée d\'étude et des ressources d\'ateliers','https://github.com/robillardstudio/itmai',1,NULL),
(87548,16144,339,NULL,'literal','','La conférence explore les défis éthiques posés par l\'intelligence artificielle (IA) et le capitalisme de plateforme, en mettant en lumière les approches méthodologiques adoptées par Fabien et Konstantin dans leurs recherches respectives. Konstantin souligne l\'importance de la transparence des données et des modèles open source pour identifier et corriger les biais potentiels dans les prédictions algorithmiques, plaidant pour un environnement où la critique et l\'amélioration sont possibles. Fabien, quant à lui, s\'appuie sur la théorie critique pour analyser les implications sociales et économiques de l\'IA, notamment dans le contexte du capitalisme numérique et algorithmique. Il souligne l\'importance de contextualiser l\'usage de ces technologies dans un cadre global qui prend en compte les intérêts économiques qu\'elles servent, notamment après la privatisation d\'entités comme OpenAI. La discussion aborde également l\'impact des agents algorithmiques dans la politique, illustré par leur rôle dans les réseaux sociaux lors d\'événements électoraux, et appelle à une plus grande transparence et réglementation pour garantir l\'intégrité de ces systèmes. L\'accent est mis sur la nécessité de maintenir un dialogue éthique continu, en intégrant des perspectives critiques pour comprendre les dynamiques complexes et contradictoires du champ social dans lequel l\'IA évolue.',NULL,1,NULL),
(87549,16144,2097,15083,'resource',NULL,NULL,NULL,1,NULL),
(87550,16144,2097,13669,'resource',NULL,NULL,NULL,1,NULL),
(87552,16144,2097,13476,'resource',NULL,NULL,NULL,1,NULL),
