(87594,16148,1,NULL,'literal','','Deepfakes ou synthèse vocale',NULL,1,NULL),
(87595,16148,386,16141,'resource',NULL,NULL,NULL,1,NULL),
(87596,16148,7,NULL,'numeric:timestamp',NULL,'2023-10-12',NULL,1,NULL),
(87597,16148,19,NULL,'literal','','La présentation portera sur les deepfakes dans le domaine sonore, et sur des problématiques en lien avec les domaines du journalisme et des médias. Mais la synthèse vocale est aussi un sujet plus large qui irrigue de nombreuses pratiques créatives. La présentation ouvrira donc sur des projets élaborés en collaboration avec des artistes, cinéastes ou compositeurs.',NULL,1,NULL),
