(87656,16159,1,NULL,'literal','','Après l’intelligence artificielle, l’éthique, les tics, l’esthétique',NULL,1,NULL),
(87657,16159,386,16157,'resource',NULL,NULL,NULL,1,NULL),
(87658,16159,7,NULL,'numeric:timestamp',NULL,'2023-10-12',NULL,1,NULL),
(87659,16159,19,NULL,'literal','','Sur la scène culturelle, médiatique et fantasmatique, l’Intelligence Artificielle et l’Ingénierie Ambiante occupent une place grandissante. Au moment où elles semblent défier la créativité humaine, on leur accorde toutes les vertus et tous les maléfices, par un effet de symétrie entre messianisme et catastrophisme. Les apôtres de la désinhibition technologique, tout comme les éreinteurs du présent, offrent trop peu de prise sur la manière d’habiter, d’inventer, de hanter un monde possible. Dans cette contribution à la journée d’étude du Fresnoy, il sera question d’apprentissage machine et de désapprentissage humain, de la conversion d’un médium dans l’autre et de l’intraductible, du possible et de l’improbable.',NULL,1,NULL),
