(89024,16355,1,NULL,'literal','','Une vie intelligente :  les défis d’une création qui explore l’IA',NULL,1,NULL),
(89025,16355,386,14427,'resource',NULL,NULL,NULL,1,NULL),
(89026,16355,386,16352,'resource',NULL,NULL,NULL,1,NULL),
(89027,16355,7,NULL,'numeric:timestamp',NULL,'2024-11-08',NULL,1,NULL),
(89028,16355,19,NULL,'literal','','« Une vie intelligente » est aussi le titre du spectacle qui sera présenté en mars chez Duceppe à Montréal.\nLa présentation porte sur la Déclaration de Montréal, adoptée en 2018, qui propose 10 règles pour une IA responsable. Le groupe, issu du milieu universitaire, du milieu de l’industrie numérique et de la société civile à la base de cette déclaration a choisi d’en diffuser le contenu sous forme de pièce de théâtre pour sensibiliser le public le plus large possible aux risques que posent certains usages de l’IA.\nAprès avoir présenté la Déclaration, Jean-Marc Larrue et Dominique Leclerc discuteront des défis que pose la création d’une oeuvre théâtrale sur ce sujet complexe.',NULL,1,NULL),
(89029,16355,339,NULL,'literal','','La conférence explore le processus créatif de la pièce \"Une vie intelligente\", dirigée par Dominique Leclerc et Patrice Charbonneau Brunel, qui sera présentée à Montréal en février et mars prochains. Le spectacle, produit par la compagnie Post-Humain, aborde les impacts des technologies NBIC sur le vivant, en mettant l\'accent sur l\'intelligence artificielle (IA). Leclerc, co-fondatrice de la compagnie, s\'inspire de la Déclaration de Montréal sur l\'IA responsable pour élaborer un récit qui intègre des perspectives citoyennes et non-expertes, tout en évitant l\'utilisation de technologies IA dans la production elle-même. La pièce vise à sensibiliser un public large, notamment celui du théâtre Jean Duceppe, à des questions éthiques et environnementales liées à l\'IA, tout en cherchant à offrir une prise de conscience et des pistes d\'action concrètes. Le processus de création inclut des témoignages audio et des contributions de non-acteurs, tels qu\'un doctorant en éthique des machines et une journaliste spécialisée en prospective, pour enrichir le dialogue sur les enjeux contemporains de l\'IA. Le défi réside dans la capacité à capter l\'évolution rapide de l\'IA et à traduire ces dynamiques complexes dans un format théâtral accessible et engageant, tout en maintenant une réflexion sur l\'impact environnemental et sociétal de ces technologies.',NULL,1,NULL),
