(89804,16469,386,16466,'resource',NULL,NULL,NULL,1,NULL),
(89805,16469,7,NULL,'numeric:timestamp',NULL,'2024-11-22',NULL,1,NULL),
(89806,16469,19,NULL,'literal',NULL,'On constate depuis au moins une dizaine d’années la multiplication des revendications à être « scientifique ». Ou au contraire à déclarer qu’un discours ou une notion n’est pas scientifique. Un bel exemple est fourni par la direction du CNRS en France qui, pris au piège par une demande la Ministre de l’enseignement supérieur d’enquêter sur « l’islamogauchisne » à l’université avait déclaré : « L’Islamogauchisme n’est pas une réalité scientifique » (je souligne). Partant de l’analyse du sens de cette phrase je tenterai de montrer comment la recherche de la vérité (comme adéquation aux phénomènes observés) dépend d’une capacité d’analyse rationnelle qui obéit à certaines règles universelles.',NULL,1,NULL),
