(89813,16470,1,NULL,'literal',NULL,'L’intelligence est forcément artificielle: peurs déplacées et dangers ignorés',NULL,1,NULL),
(89814,16470,386,14440,'resource',NULL,NULL,NULL,1,NULL),
(89815,16470,7,NULL,'numeric:timestamp',NULL,'2024-11-22',NULL,1,NULL),
(89816,16470,19,NULL,'literal',NULL,'Depuis la sortie en novembre 2022 de chatGPT, l’espace médiatique se remplit de discours sur l\' »intelligence artificielle ». Une thématique récurrente dans les débats est celle du rapport humain-machine qui voit opposer l’intelligence artificielle à une intelligence qui serait « humaine ». Le danger des approches computationnelles serait donc qu’ils menacerait la place des êtres humains ou alors qu’elles produiraient des « résultats » inférieurs à ceux que peuvent produire les êtres humains. Dans ma présentation je vais d’abord questionner l’expression « intelligence artificielle » et introduire l’idée de « modèles de définition de l’intelligence » pour montrer ensuite que les véritables enjeux  des approches computationnels ne sont pas dans l’opposition entre humain et machine, mais plutôt ailleurs : dans les dispositifs politiques, économiques et culturels qui déterminent leur industrialisation.',NULL,1,NULL),
