(91278,16740,1,NULL,'literal',NULL,'Considérations juridico-éthiques liées à l’IA générative dans les domaines judiciaire et culturel : perspectives européennes',NULL,1,NULL),
(91279,16740,386,16492,'resource',NULL,NULL,NULL,1,NULL),
(91280,16740,7,NULL,'numeric:timestamp',NULL,'2024-11-29',NULL,1,NULL),
(91281,16740,19,NULL,'literal',NULL,'L’IA générative bouleverse les secteurs d’activités et fait émerger des enjeux éthiques et juridiques liés aux droits fondamentaux, à la responsabilité et à la propriété intellectuelle. De nombreux travaux réglementaires ont été menés au niveau européen pour tenter d’encadrer ce phénomène technologique. L’intervention portera sur un état des lieux de ces enjeux, du droit applicable et des considérations éthiques liées à l’IA dans différents secteurs, tout particulièrement le secteur de la justice et celui de la culture.',NULL,1,NULL),
