(91290,16740,36,16802,'resource',NULL,NULL,NULL,1,NULL),
(91291,16741,1,NULL,'literal',NULL,'Revoir le droit d’auteur à la lumière de l’IA générative',NULL,1,NULL),
(91292,16741,386,16494,'resource',NULL,NULL,NULL,1,NULL),
(91293,16741,7,NULL,'numeric:timestamp',NULL,'2024-11-29',NULL,1,NULL),
(91294,16741,19,NULL,'literal',NULL,'Depuis que ChatGPT est devenu un phénomène connu du grand public, les répercussions de l’intelligence artificielle générative sur la création artistique, qu’elle soit littéraire ou autre, monopolisent une grande partie des discussions de la communauté du droit d’auteur.  Les avancées technologiques ont toujours provoqué une réévaluation des principes généraux du ce droit.  Cette présentation aura pour but de sensibiliser le milieu littéraire à ces discussions pour lui permettre de mieux comprendre la dimension juridique, propre au droit d’auteur, de l’impact de l’IA générative sur la création littéraire.',NULL,1,NULL),
