(114054,21231,386,17230,'resource',NULL,NULL,NULL,1,NULL),
(114157,21231,7,NULL,'numeric:timestamp',NULL,'2026-01-28',NULL,1,NULL),
(114158,21231,19,NULL,'literal','','La conférence de Julie-Michel Morin examine comment les récits entourant l’intelligence artificielle façonnent les imaginaires et la gouvernance sociotechniques. Elle analyse les stratégies narratives de l’industrie technologique et plaide pour une pluralité de récits afin de critiquer le réalisme algorithmique et rouvrir le débat public sur l’IA.',NULL,1,NULL),
(114159,21231,339,NULL,'literal','','La conférence de Julie-Michel Morin, intitulée \"Gouverner par les récits, l\'IA comme dispositif narratif\", explore les pratiques narratives entourant l\'intelligence artificielle (IA) et leur rôle dans la gouvernance sociotechnique. Morin, chercheure postdoctorale et artiste-chercheure, s\'intéresse à la manière dont les récits autour de l\'IA, notamment ceux issus du milieu techno-industriel, sont utilisés pour spectaculariser la technologie et influencer les imaginaires sociotechniques. Elle identifie plusieurs stratégies narratives, telles que la promesse de transformation radicale, le récit d\'inévitabilité et l\'anthropomorphisation des IA, qui contribuent à structurer des imaginaires collectifs et à influencer les formes de gouvernance. Ces récits, en effaçant les médiations et en naturalisant les capacités des IA, rendent difficile la critique et l\'exploration d\'alternatives. Morin propose une approche pluraliste pour analyser ces récits, en utilisant la plateforme EdiSem pour documenter et comparer les récits techno-industriels, médiatiques, scientifiques, citoyens et artistiques. Elle s\'appuie sur le concept de réalisme algorithmique pour expliquer comment les récits dominants rendent certaines trajectoires technologiques inévitables. En réponse, elle plaide pour une pluralisation des récits afin de rouvrir l\'espace du débat public et de rendre visibles les choix technologiques. Cette approche vise à désarticuler le cadre idéologique dominant et à promouvoir une compréhension plus nuancée et critique de l\'IA dans la société contemporaine.',NULL,1,NULL),
