(114240,21220,7,NULL,'numeric:timestamp',NULL,'2026-01-28',NULL,1,NULL),
(114241,21220,19,NULL,'literal','','La conférence de Fabien Richert analyse la conceptualisation de l’intelligence artificielle générale (AGI) à travers les théories du complot, révélant leurs parallèles narratifs et idéologiques. Il montre comment les discours alarmistes sur l’AGI entretiennent le hype technologique, influencent les perceptions et investissements, et naturalisent une idéologie technologique dominante qu’il propose de déconstruire.',NULL,1,NULL),
(114242,21220,339,NULL,'literal','','La conférence de Fabien explore la conceptualisation de l\'intelligence artificielle générale (AGI) à travers le prisme des théories du complot, en soulignant les parallèles narratifs et idéologiques entre ces deux domaines. L\'AGI, bien qu\'encore hypothétique, est souvent associée à des discours alarmistes sur les risques existentiels pour l\'humanité, réminiscents des structures des théories du complot. Fabien propose d\'examiner comment ces discours, en circulant parmi les élites technologiques et les médias, contribuent à un \'hype\' technologique, influençant à la fois les investissements financiers et les perceptions publiques. Il s\'appuie sur des cadres théoriques issus des études culturelles et de l\'économie politique pour analyser les mécanismes d\'interpellation et la performativité de ces discours. En outre, il envisage de cartographier les acteurs clés de ces discours et d\'évaluer leur impact dans les sphères médiatique et financière. Fabien souligne également l\'importance de contextualiser historiquement ces récits dans l\'évolution de l\'IA, marquée par des cycles d\'euphorie et de désillusion. Il met en garde contre la naturalisation de l\'AGI comme un développement inévitable, ce qui pourrait occulter les enjeux éthiques et sociétaux réels posés par l\'IA générative actuelle. Enfin, il propose une approche critique des discours de l\'AGI, en les comparant aux théories du complot pour démystifier leur influence et comprendre leur rôle dans la construction d\'une idéologie technologique dominante.',NULL,1,NULL),
