(114299,21287,7,NULL,'numeric:timestamp',NULL,'2026-02-11',NULL,1,NULL),
(114300,21287,19,NULL,'literal','','Lors de cette conférence, Laura Shackleford analyse le roman Ascension de Steve Tomasula comme une généalogie critique post-humaniste des écosystèmes algorithmiques. Elle montre comment la structure du roman, articulée autour de trois périodes historiques à Asunción, au Paraguay, retrace l’évolution de l’informatique depuis le XIXᵉ siècle jusqu’à un futur marqué par les crises écologiques et politiques. En interrogeant les récits de l’intelligence artificielle et de la technosphère, Shackleford met en avant le rôle des fictions dans la construction d’une conscience écologique et dans la réflexion sur les devenirs humains et technologiques.\n\n',NULL,1,NULL),
(114301,21288,1,NULL,'literal','','Les techniques d\'écriture de scénario, du livre à l\'IA',NULL,1,NULL),
(114302,21288,386,14459,'resource',NULL,NULL,NULL,1,NULL),
(114303,21288,7,NULL,'numeric:timestamp',NULL,'2026-02-11',NULL,1,NULL),
(114304,21288,19,NULL,'literal','','Dans cette conférence, Sylvie Leleu-Merviel retrace l’évolution des techniques d’écriture de scénarios depuis les travaux fondateurs de Vladimir Propp jusqu’aux approches contemporaines de John Truby et Robert McKee. Elle montre que l’écriture scénaristique repose sur une méthodologie rigoureuse, loin du mythe de l’inspiration spontanée. L’exposé aborde aussi l’apport et les limites de l’intelligence artificielle à travers l’exemple de l’outil Genario, en soulignant que si l’IA peut assister l’analyse des récits, elle reste dépourvue de véritable créativité et d’innovation artistique.',NULL,1,NULL),
(114363,21287,339,NULL,'literal','','Lors de cette conférence, Laura Shackleford, professeure au Rochester Institute of Technology, explore le roman \"Ascension\" de Steve Tomasula, en mettant en lumière sa capacité à offrir une généalogie critique post-humaniste des écosystèmes algorithmiques. Shackleford analyse comment le roman, à travers une narration riche et inventive, retrace l\'évolution de l\'informatique depuis la modernité du XIXe siècle jusqu\'à un futur proche marqué par des crises environnementales et des régimes autoritaires. En interrogeant les représentations narratives de l\'intelligence artificielle et des systèmes mondiaux, elle souligne l\'importance de nouveaux modes de narration pour appréhender les défis contemporains. Le roman est structuré autour de trois périodes historiques à Asunción, chacune illustrant des transformations paradigmatiques dans notre compréhension du monde naturel et technologique. Shackleford met en avant l\'idée que ces récits permettent de reconsidérer notre relation à la technosphère, un concept qui décrit l\'intégration croissante des technologies dans les infrastructures matérielles. Elle souligne également le potentiel des récits pour encourager une conscience écologique et une action collective face à l\'Anthropocène. Enfin, la discussion s\'élargit à la manière dont d\'autres œuvres littéraires et théoriques abordent ces questions, en questionnant les implications d\'une vision post-humaniste qui pourrait parfois glisser vers un anti-humanisme, tout en cherchant à comprendre les trajectoires futures de l\'humanité face à ses propres créations technologiques.',NULL,1,NULL),
