(115768,21575,1,NULL,'literal','','L\'intelligence artificielle comme milieu narratif et esthétique',NULL,1,NULL),
(115769,21575,386,21463,'resource',NULL,NULL,NULL,1,NULL),
(115770,21575,7,NULL,'numeric:timestamp',NULL,'2026-03-11',NULL,1,NULL),
(115771,21575,19,NULL,'literal','','La conférence d’Eva Raggini explore comment l’intelligence artificielle devient un milieu narratif et esthétique partagé entre humain et machine. Elle s’appuie sur une généalogie de l’art algorithmique, expose les architectures modernes et le rôle central du prompt comme interface de création. Raggini présente ensuite des études de cas montrant comment l’IA intervient dans l’écriture, le design visuel et les workflows de production. ',NULL,1,NULL),
(115775,21575,339,NULL,'literal','','Cette conférence synthétise une thèse de recherche‑création qui positionne l\'intelligence artificielle non comme simple outil mais comme milieu narratif et esthétique co‑actif, redéfinissant l\'acte créatif par un dialogue humain‑algorithmique où le prompt, les architectures (GAN, transformers, modèles de diffusion et diffusion latente) et les dispositifs de conditionnement (ControlNet, LoRa, Confi UI) opèrent conjointement pour articuler exploration, contrôle et direction artistique; l\'approche transdisciplinaire lie une généalogie de l\'art algorithmique aux fondements techniques contemporains, explicite les mécanismes de génération et de guidage, et met en regard expérimentations (storyboards, courts‑métrages, prototypes, animation neuronale) et exigences de cohérence visuelle en production cinéma/jeu vidéo. La thèse interroge la temporalité, l\'infinité de variation et les attracteurs esthétiques des modèles, propose des stratégies de détournement pour préserver singularité et continuité, et formalise une méthodologie reproductible reliant théorie, prototypage et pipeline professionnel. Elle conclut en appelant à une épistémologie critique, à une refondation des formations artistiques et à de nouveaux critères d\'évaluation des œuvres générées, replaçant l\'artiste en explorateur capable de contraindre, composer et donner forme à des systèmes génératifs.',NULL,1,NULL),
(115782,21579,1,NULL,'literal','','IA et créativité dans les arts numériques',NULL,1,NULL),
(115783,21579,386,21577,'resource',NULL,NULL,NULL,1,NULL),
(115784,21579,7,NULL,'numeric:timestamp',NULL,'2026-03-11',NULL,1,NULL),
(115785,21579,19,NULL,'literal','','La conférence d’Alain Lioret présente 20 ans de recherche sur l’art génératif, des Being Paintings aux Live Beings, conçus comme des entités numériques autonomes émergeant de règles simples dans des espaces complexes. Il mobilise automates cellulaires, algorithmes génétiques, réseaux de neurones et calcul quantique pour produire des comportements imprévisibles, en opposition à la génération statistique des LLM. Lioret critique ces derniers, limités au texte, et met en avant les World Models de Yann LeCun, qui apprennent une représentation causale du monde à partir de données physiques. La conférence conclut sur l’idée d’une créativité artificielle incarnée, fondée sur l’émergence et l’interaction avec un environnement réel ou simulé.',NULL,1,NULL),
(115786,21579,339,NULL,'literal','','La conférence explore l\'intersection de l\'intelligence artificielle (IA) et de la créativité dans les arts numériques, en mettant l\'accent sur une approche alternative à celle des modèles de langage (LLM). L\'orateur retrace 24 ans de recherche sur l\'art génératif, en commençant par les Being Paintings jusqu\'aux Live Beings, illustrant une généalogie de l\'émergence artificielle. Les algorithmes utilisés incluent des automates cellulaires, des algorithmes génétiques, des réseaux de neurones et le calcul quantique, soulignant une quête de comportements imprévus et autonomes. La présentation questionne la créativité des LLM, souvent perçus comme limités par leur dépendance à des données préexistantes, et propose une alternative par l\'émergence, où des entités numériques évoluent de manière autonome dans des environnements complexes. L\'introduction des World Models, inspirés par Yann Lequin, ouvre de nouvelles perspectives en IA, visant à comprendre et interagir avec le monde réel plutôt que de se limiter à la prédiction textuelle. Cette approche s\'aligne avec les travaux de l\'orateur, cherchant à créer des entités numériques véritablement vivantes et esthétiquement innovantes. La conférence conclut sur l\'avenir des World Models comme une extension des approches émergentes, promettant une créativité incarnée et une interaction plus profonde avec le monde physique.',NULL,1,NULL),
