(117184,21920,1,NULL,'literal','','Mettre en scène l’IA : récits, idéologies et pratiques artistiques',NULL,1,NULL),
(117185,21920,386,16352,'resource',NULL,NULL,NULL,1,NULL),
(117186,21920,7,NULL,'numeric:timestamp',NULL,'2025-03-26',NULL,1,NULL),
(117187,21920,19,NULL,'literal','','La conférence présente une démarche artistique sur le transhumanisme et l’IA, mêlant enquêtes empiriques, performance et dispositifs participatifs pour questionner le  contrôle, le consentement et l\'espoir technologique. Elle s’appuie sur des terrains variés (biohackers, entretiens publics, récits autobiographiques) pour créer une « zone grise » entre adhésion et rejet. Théâtre et cinéma deviennent des outils de littératie numérique et de délibération démocratique, inspirés notamment par la Déclaration de Montréal sur l’IA responsable, afin de transformer les spectateurs en citoyens capables d’un consentement éclairé face aux technologies.',NULL,1,NULL),
(117188,21920,339,NULL,'literal','','La conférence articule une démarche artistique-investigative centrée sur le transhumanisme et l\'intelligence artificielle en tissant enquêtes empiriques, pratiques scéniques et dispositifs participatifs afin de problematiser contrôle, espérance technologique et consentement. L\'oratrice retrace un continuum de terrains — rencontres avec biohackers berlinois, entretiens publics (notamment avec des figures de l\'IA), cas autobiographiques (diabète, implants cochléaires) — pour construire une « zone grise » critique entre adhésion et rejet, où la médecine, la performance technologique et les récits transhumanistes se confondent. Le théâtre et le cinéma sont mobilisés comme espaces de littératie numérique et de prospective démocratique : formats longs, séquences de co-création avec le public et intégration de la Déclaration de Montréal visent à transformer spectateurs en acteurs informés capables d\'exercer un consentement éclairé. Face à la vitesse d\'obsolescence conceptuelle et à une techno-anxiété croissante, la démarche privilégie la friction conceptuelle et la mise en dialogue interdisciplinaire plutôt que des réponses définitives, propose des solutions pratiques (plateformes alternatives, ateliers) et souligne la nécessité d\'espaces collectifs pour déployer nuance, débat et éducation civique autour des enjeux éthiques de l\'IA.',NULL,1,NULL),
(117189,21921,1,NULL,'literal','','Les barrières à l\'emploi de l\'IA générative dans le cinéma indépendant',NULL,1,NULL),
(117190,21921,386,18864,'resource',NULL,NULL,NULL,1,NULL),
(117191,21921,7,NULL,'numeric:timestamp',NULL,'2026-03-26',NULL,1,NULL),
(117192,21921,19,NULL,'literal','','Jeremy Peter Allan examine comment intégrer l’IA générative au cinéma sans sacrifier l’apport humain ni accentuer les coûts sociaux et environnementaux. À partir d’un modèle hybride mêlant tournage en studio et génération par IA, il souligne l’importance du jeu d’acteur, les limites techniques actuelles, l’incertitude juridique et les tensions professionnelles qu’entraîne cette technologie. Il met aussi en évidence des freins culturels et écologiques, puis propose des solutions techniques et institutionnelles pour encadrer l’usage de l’IA. Il plaide finalement pour une adoption critique, locale et régulée au service du cinéma indépendant.',NULL,1,NULL),
(117193,21921,339,NULL,'literal','','Le conférencier, cinéaste indépendant et chercheur, articule une problématique centrale : comment intégrer l\'IA générative au cinéma sans évacuer la composante humaine ni aggraver les effets environnementaux et sociaux du secteur. En expérimentant un modèle hybride — tournage avec comédiens en studio servant de driving video pour générer par IA décors et nourrissons — il met en relief la dépendance au jeu d\'acteur pour la subtilité expressive, les limites actuelles des modèles (dérive d\'apparence des interprètes, biais de génération, effet d\'uncanny valley, imprévisibilité incompatible avec des calendriers de production) et le flou juridique autour des droits d\'auteur, tout en observant la polarisation entre praticiens pro‑IA et anti‑IA et les pressions syndicales. Par des entretiens et un enseignement centré sur l\'éco‑fiction, il identifie l\'AI shaming, la standardisation esthétique et la crainte climatique comme barrières, et propose des solutions techniques et institutionnelles : serveurs locaux open source alimentés par électricité renouvelable, normes limitant le remplacement humain et stratégies de maillage entre réseaux alternatifs et infrastructures traditionnelles pour préserver les revenus des créateurs. Sa conclusion appelle à une intégration critique et encadrée de l\'IA afin d\'assurer la viabilité créative et économique du cinéma indépendant.',NULL,1,NULL),
