(121611,22886,1,NULL,'literal','','IA générative et pipelines en recomposition : enjeux pédagogiques en situation de production',NULL,1,NULL),
(121612,22886,386,22887,'resource',NULL,NULL,NULL,1,NULL),
(121613,22886,7,NULL,'numeric:timestamp',NULL,'2026-04-15',NULL,1,NULL),
(121620,22889,1,NULL,'literal','','Les IA en partenaires : créer de nouveaux narratifs sur nos relations avec la technologie via la scène',NULL,1,NULL),
(121621,22889,386,22890,'resource',NULL,NULL,NULL,1,NULL),
(121622,22889,7,NULL,'numeric:timestamp',NULL,'2026-04-15',NULL,1,NULL),
(121766,22889,19,NULL,'literal','','La conférence propose de reconfigurer les relations entre humains et IA dans les arts vivants, en faisant de l’IA un partenaire de jeu plutôt qu’un outil trompeur ou menaçant. Ancrée dans l’anthropologie de la nature, la philosophie des techniques et la théorie de l’acteur‑réseau, la démarche repose sur l’improvisation en mouvement, la transduction du geste en son et l’usage d’algorithmes small data (k‑NN, chaînes de Markov, régressions). Cette approche révèle des dynamiques d’appropriation progressive, une transformation des motifs chorégraphiques et une agentivité distribuée où la machine, moins autonome individuellement, renforce l’agentivité du collectif et alimente un more‑than‑human‑centered design.',NULL,1,NULL),
(121767,22889,339,NULL,'literal','','La conférence articule une thèse claire et opératoire : reconfigurer les narratifs et les dispositifs relationnels entre humains et intelligences artificielles au sein des arts vivants afin de produire des collectifs hybrides où l’IA tient le rôle de partenaire de jeu plutôt que d’outil trompeur ou menaçant. À partir d’un ancrage théorique mêlant anthropologie de la nature, philosophie des techniques et théories de l’acteur‑réseau, l’intervenante expose une méthodologie empirique centrée sur l’improvisation en mouvement, la transduction du geste en données sonores et l’entraînement itératif d’ensembles d’algorithmes « small data » (k‑nearest neighbors, chaînes de Markov, régressions) plutôt que de modèles larges, ce qui permet d’ajuster esthétique sonore, sensibilité du dispositif et perceptions des interprètes. L’analyse conceptuelle de la « connexion » scénique et la typologie des attitudes interprètes révèlent des dynamiques d’appropriation graduelles et une transformation des motifs chorégraphiques ; simultanément la recherche propose de repenser l’agentivité technologique : dans un collectif performatif, l’autonomie individuelle de la machine peut être moindre tout en contribuant à l’agentivité du groupe. Ces conclusions nourrissent une proposition pratique pour le more‑than‑human‑centered design et ouvrent la voie à un triptyque narratif futur explorant relations de genre et non‑humain.',NULL,1,NULL),
