(122450,23116,1,NULL,'literal','','Le bien-être au travail en environnement hybride comme phénomène situé',NULL,1,NULL),
(122451,23116,386,21179,'resource',NULL,NULL,NULL,1,NULL),
(122452,23116,339,NULL,'literal','','La présentation propose un projet de maîtrise en design concevant le bien‑être au travail en contexte hybride comme phénomène situé, liant critique des modèles standardisés (Activity Based Workspaces) — qui instaurent flexibilité apparente et contraintes décisionnelles quotidiennes — à la fragmentation identitaire résultant du désancrage spatial; le cadre théorique combine la théorie de l\'autodétermination, le modèle Job Demand‑Resources et la neuroarchitecture pour penser la satisfaction des besoins d\'autonomie, compétence et affiliation à l\'aune des ressources spatiales et sensorielles, et intègre des perspectives collectives (éthique du care, théorie des communs, holding environment) qui traitent l\'espace comme ressource partagée et milieu matériel porteur d\'attachement. La méthodologie est qualitative, située et bidirectionnelle, mobilisant phénoménologie, théorie ancrée et collecte multimodale (entretiens, observations, photo‑élicitation, objets) afin de transformer récits vécus en recommandations spatiales opérationnelles; une expérimentation avec outils d\'IA générative et pipeline automatisé (Canva, Firefly, Runway, M‑U10, Olama, N8N) a permis d\'élaborer un corpus étendu et d\'identifier limites (son, durée, réalisme) et itérations nécessaires pour combler le fossé recherche‑pratique et outiller le designer comme médiateur de situations situées.',NULL,1,NULL),
